arguments.new_str:
using Microsoft.EntityFrameworkCore;
class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(b =>
        {
            // EF Core 9 renamed the discriminator property from "Discriminator" to "$type".
            // Keep the old name so existing documents and raw SQL queries still work.
            b.HasDiscriminator<string>("Discriminator");

            // EF Core 9 no longer prepends the discriminator to the JSON id.
            // Keep the old "Blog|1" format so existing documents are found.
            b.HasDiscriminatorInJsonId();
        });
    }
}

